def my_pow(x: float, n: int) -> float:
    if n == 0:
        return 1.0
    neg = n < 0
    if neg:
        x = 1.0 / x
        n = -n
    res = 1.0
    base = x
    while n > 0:
        if n & 1:
            res *= base
        base *= base
        n >>= 1
    return res

